const item = $input.first().json;
const b = item.body || {};
const service = String(b.service_name != null && b.service_name !== '' ? b.service_name : 'unknown');
const evidenceArr = Array.isArray(b.evidence) ? b.evidence : [];
const evidenceSummary = [];
for (let i = 0; i < evidenceArr.length && evidenceSummary.length < 12; i++) {
  const e = evidenceArr[i];
  if (!e || typeof e !== 'object') continue;
  const r = e.reason || '';
  const s = e.source || '';
  const t = e.type || '';
  const line = (r && s) ? (r + ' — ' + s) : (r || s || t);
  if (line) evidenceSummary.push(String(line));
}
const rec = b.recommended_actions;
const actions = Array.isArray(rec) ? rec.map(function (a) { return String(a); }) : [];
var conf = b.confidence;
var confStr = (conf != null && conf !== '') ? String(conf) : 'n/a';
var rc = b.likely_root_cause || 'n/a';
var summary = b.incident_summary || 'Incident';
function cap(s, n) {
  s = String(s);
  return s.length > n ? s.substring(0, n) + '…' : s;
}
var fields = [
  { title: 'Service', value: cap(service, 200), short: true },
  { title: 'Confidence', value: cap(confStr, 200), short: true },
  { title: 'Likely root cause', value: cap(rc, 2000), short: false },
  { title: 'Actions', value: cap(actions.length ? actions.map(function (a) { return '• ' + a; }).join('\n') : 'n/a', 2000), short: false },
  { title: 'Evidence summary', value: cap(evidenceSummary.length ? evidenceSummary.map(function (e) { return '• ' + e; }).join('\n') : 'n/a', 2000), short: false },
];
var payload = {
  text: '🚨 CRITICAL: ' + cap(summary, 500) + ' (' + service + ', conf ' + confStr + ')',
  attachments: [
    {
      color: 'danger',
      title: '🚨 CRITICAL Incident Detected',
      fields: fields,
    },
  ],
};
return [{ json: { slackPost: payload } }];

